            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"as1","text":"You've received a new CNC mill from Haas. What's the first step to add it in Forge?","options":[{"id":"a","text":"Go to Admin → Equipment and register the serial number"},{"id":"b","text":"Go to Assets, click Add Asset, and fill in the name, type (Machine), manufacturer (Haas), and location","isCorrect":true},{"id":"c","text":"Create a Job on the Kanban Board and tag it as equipment setup"},{"id":"d","text":"Add it to Inventory as a new storage location"}],"explanation":"New equipment goes in the Assets module. Click Add Asset, pick type Machine, and fill in the details. The asset starts as Active."},{"id":"as2","text":"A customer sends you a mold they own for production. How do you track it in Forge?","options":[{"id":"a","text":"Add an Asset with type Tooling and turn on Customer Owned","isCorrect":true},{"id":"b","text":"Add it as a Part in the Parts Catalog with status Draft"},{"id":"c","text":"Create a Purchase Order to record its receipt"},{"id":"d","text":"Add it to Inventory as received stock"}],"explanation":"Customer-owned tooling is a Tooling asset with Customer Owned turned on. That sets it apart in reports and keeps it handled correctly."},{"id":"as3","text":"An asset shows a status of 'Out of Service' (red). What does that mean?","options":[{"id":"a","text":"The asset is scheduled for routine maintenance next week"},{"id":"b","text":"The asset has been permanently retired and will be sold"},{"id":"c","text":"The asset is broken or otherwise unavailable — an unplanned outage","isCorrect":true},{"id":"d","text":"The asset's operating hours have passed its service life"}],"explanation":"Out of Service (red) means an unplanned outage — the asset is broken or unavailable. That's different from Maintenance (yellow, planned downtime) and Retired (gray, taken out for good)."},{"id":"as4","text":"You want